(3, 'Tartine avocat & graines', 'Écraser l\'avocat sur pain complet toasté, ajouter graines, citron, sel et poivre.', 10, 'Facile', 'A+', 1, '2026-04-14 20:12:24', '2026-04-14 20:12:24', 1, 14),
