(5, 'Curry de lentilles vertes', 'Cuire lentilles avec oignons, épices, tomate. Servir avec riz complet.', 40, 'Moyen', 'A', 4, '2026-04-14 20:12:24', '2026-04-14 20:12:24', 1, 11),
(6, 'Bol de quinoa aux brocolis', 'Cuire quinoa, brocoli vapeur, ajouter amandes et vinaigrette citron.', 20, 'Facile', 'A', 2, '2026-04-14 20:12:24', '2026-04-15 12:19:54', 1, 14),
(7, 'Salade de patate douce', 'Cuire les patates douces, les couper en dés, ajouter les épinards, les pois chiches et une vinaigrette au citron.', 25, 'Facile', 'A', 2, '2026-05-11 20:00:00', '2026-05-11 20:00:00', 1, 15);

