--
-- Structure de la vue `v_avis_recents`
--
DROP TABLE IF EXISTS `v_avis_recents`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `v_avis_recents`  AS SELECT `a`.`id` AS `id`, `a`.`recette_id` AS `recette_id`, `r`.`titre` AS `recette_titre`, `a`.`utilisateur_nom` AS `utilisateur_nom`, `a`.`note` AS `note`, `a`.`commentaire` AS `commentaire`, `a`.`date_creation` AS `date_creation`, `a`.`est_modere` AS `est_modere` FROM (`avis` `a` join `recettes` `r` on(`a`.`recette_id` = `r`.`id`)) WHERE `a`.`est_modere` = 1 ORDER BY `a`.`date_creation` DESC LIMIT 0, 10 ;

-- --------------------------------------------------------

--
-- Structure de la vue `v_ingredients_stats`
--
DROP TABLE IF EXISTS `v_ingredients_stats`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `v_ingredients_stats`  AS SELECT `i`.`id` AS `id`, `i`.`nom` AS `nom`, `i`.`calories` AS `calories`, `i`.`eco_score` AS `eco_score`, count(distinct `ri`.`recette_id`) AS `nombre_utilisations`, round(avg(`ri`.`quantite`),2) AS `quantite_moyenne` FROM (`ingredients` `i` left join `recette_ingredient` `ri` on(`i`.`id` = `ri`.`ingredient_id`)) GROUP BY `i`.`id` ;

-- --------------------------------------------------------

--
-- Structure de la vue `v_recettes_details`
--
DROP TABLE IF EXISTS `v_recettes_details`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `v_recettes_details`  AS SELECT `r`.`id` AS `id`, `r`.`titre` AS `titre`, `r`.`instruction` AS `instruction`, `r`.`temps_preparation` AS `temps_preparation`, `r`.`difficulte` AS `difficulte`, `r`.`eco_score` AS `eco_score`, `r`.`nombre_portions` AS `nombre_portions`, count(distinct `ri`.`ingredient_id`) AS `nombre_ingredients`, count(distinct `a`.`id`) AS `nombre_avis`, coalesce(round(avg(`a`.`note`),1),0) AS `note_moyenne`, `u`.`nom` AS `auteur_nom` FROM (((`recettes` `r` left join `recette_ingredient` `ri` on(`r`.`id` = `ri`.`recette_id`)) left join `avis` `a` on(`r`.`id` = `a`.`recette_id`)) left join `utilisateurs` `u` on(`r`.`utilisateur_id` = `u`.`id`)) WHERE `r`.`est_actif` = 1 GROUP BY `r`.`id` ;

-- --------------------------------------------------------

--
-- Structure de la vue `v_top_recettes`
--
DROP TABLE IF EXISTS `v_top_recettes`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `v_top_recettes`  AS SELECT `r`.`id` AS `id`, `r`.`titre` AS `titre`, coalesce(round(avg(`a`.`note`),1),0) AS `note_moyenne`, count(`a`.`id`) AS `nombre_avis`, `r`.`eco_score` AS `eco_score`, `r`.`temps_preparation` AS `temps_preparation`, `r`.`difficulte` AS `difficulte` FROM (`recettes` `r` left join `avis` `a` on(`r`.`id` = `a`.`recette_id`)) WHERE `r`.`est_actif` = 1 GROUP BY `r`.`id` ORDER BY coalesce(round(avg(`a`.`note`),1),0) DESC, count(`a`.`id`) DESC ;

